# tidy ----

## Setup ----
fit <- local({
  clear()
  withr::defer(clear(), envir = parent.env(environment()))
  data("data_big", package = "FIMS")
  data_4_model <- FIMSFrame(data_big)
  create_default_parameters(
    configurations = create_default_configurations(data = data_4_model),
    data = data_4_model
  ) |>
    initialize_fims(data = data_4_model) |>
    fit_fims(optimize = TRUE)
})

## IO correctness ----
test_that("tidy() works with correct inputs", {
  #' @description Test that generics::tidy(fit) returns a tibble with expected broom and FIMS columns.
  expect_true(all(c(
    "term", "estimate", "std.error", "statistic", "p.value",
    "module_name", "module_id", "estimation_type"
  ) %in% names(generics::tidy(fit))))

  #' @description Test that generics::tidy(fit) defaults to fixed and random effects rows only.
  expect_true(all(generics::tidy(fit)[["estimation_type"]] %in%
    c("fixed_effects", "random_effects")))

  #' @description Test that generics::tidy(fit) statistic equals estimate divided by std.error.
  expect_equal(
    object = generics::tidy(fit)[["statistic"]],
    expected = generics::tidy(fit)[["estimate"]] / generics::tidy(fit)[["std.error"]]
  )

  #' @description Test that generics::tidy(fit, conf.int = TRUE) adds conf.low and conf.high columns.
  expect_true(all(c("conf.low", "conf.high") %in% names(generics::tidy(fit, conf.int = TRUE))))
})

## Edge handling ----
test_that("tidy() returns correct outputs for edge cases", {
  #' @description Test that generics::tidy(fit) does not error after clear() has been called.
  clear()
  expect_no_error(object = generics::tidy(fit))
})

## Error handling ----
test_that("tidy() returns correct error messages", {
  #' @description Test that generics::tidy(fit, parameters = "invalid") returns an error about unknown estimation type.
  expect_error(
    object = generics::tidy(fit, parameters = "invalid"),
    regexp = "unknown estimation type"
  )
})

# glance ----

## Setup ----
# Uses fit created above.

## IO correctness ----
test_that("glance() works with correct inputs", {
  #' @description Test that generics::glance(fit) returns a one-row tibble with expected columns.
  expect_equal(object = nrow(generics::glance(fit)), expected = 1L)
  expect_true(all(c(
    "logLik", "AIC", "BIC", "nobs", "npar_fixed",
    "max_gradient", "converged"
  ) %in% names(generics::glance(fit))))

  #' @description Test that generics::glance(fit) logLik equals negative marginal_nll.
  expect_equal(
    object = generics::glance(fit)[["logLik"]],
    expected = -generics::glance(fit)[["marginal_nll"]]
  )

  #' @description Test that generics::glance(fit) AIC equals 2 * npar_fixed - 2 * logLik.
  expect_equal(
    object = generics::glance(fit)[["AIC"]],
    expected = 2 * generics::glance(fit)[["npar_fixed"]] - 2 * generics::glance(fit)[["logLik"]]
  )
})

## Edge handling ----
test_that("glance() returns correct outputs for edge cases", {
  #' @description Test that generics::glance(fit) does not error after clear() has been called.
  clear()
  expect_no_error(object = generics::glance(fit))
})

## Error handling ----
# No built-in errors or warnings for glance().

# augment ----

## Setup ----
# Uses fit created above.

## IO correctness ----
test_that("augment() works with correct inputs", {
  #' @description Test that generics::augment(fit) returns a tibble with .truth, .pred, and .weight columns.
  expect_true(all(c(".truth", ".pred", ".weight") %in% names(generics::augment(fit))))

  #' @description Test that generics::augment(fit) .truth and .pred columns contain no NA values.
  expect_false(any(is.na(generics::augment(fit)[[".truth"]])))
  expect_false(any(is.na(generics::augment(fit)[[".pred"]])))

  #' @description Test that generics::augment(fit, include_weights = FALSE) omits the .weight column.
  expect_false(".weight" %in% names(generics::augment(fit, include_weights = FALSE)))

  #' @description Test that generics::augment(fit, include_weights = FALSE) still returns .truth and .pred.
  expect_true(all(c(".truth", ".pred") %in% names(generics::augment(fit, include_weights = FALSE))))
})

## Edge handling ----
test_that("augment() returns correct outputs for edge cases", {
  #' @description Test that generics::augment(fit) does not error after clear() has been called.
  clear()
  expect_no_error(object = generics::augment(fit))
})

## Error handling ----
# No built-in errors or warnings for augment() that can be triggered with a
# valid FIMSFit object. The empty-tibble warning path is a defensive guard
# for malformed model output.

# get_fit_metrics ----

## Setup ----
# Uses fit created above.

## IO correctness ----
test_that("get_fit_metrics() works with correct inputs", {
  #' @description Test that FIMS::get_fit_metrics(fit) returns a tibble with yardstick columns and default metrics rmse, mae, rsq.
  expect_true(all(c(".metric", ".estimator", ".estimate") %in%
    names(FIMS::get_fit_metrics(fit))))
  expect_setequal(
    object = FIMS::get_fit_metrics(fit)[[".metric"]],
    expected = c("rmse", "mae", "rsq")
  )

  #' @description Test that FIMS::get_fit_metrics(fit, group_by = "label") adds a label column to the output.
  expect_true("label" %in% names(FIMS::get_fit_metrics(fit, group_by = "label")))

  #' @description Test that FIMS::get_fit_metrics(fit, weighted = TRUE) returns the same metric names as unweighted.
  expect_setequal(
    object = FIMS::get_fit_metrics(fit, weighted = TRUE)[[".metric"]],
    expected = c("rmse", "mae", "rsq")
  )
})

## Edge handling ----
# Please remove/comment out the test template below if no edge cases are being tested.

## Error handling ----
test_that("get_fit_metrics() returns correct error messages", {
  #' @description Test that FIMS::get_fit_metrics(fit, group_by = "not_a_column") returns an error about column not found.
  expect_error(
    object = FIMS::get_fit_metrics(fit, group_by = "not_a_column"),
    regexp = "not found"
  )

  #' @description Test that FIMS::get_fit_metrics() returns an error when x is not a FIMSFit object.
  expect_error(
    object = FIMS::get_fit_metrics(list()),
    regexp = "FIMSFit"
  )
})

# get_fit_stream ----

## Setup ----
# Uses fit created above.

## IO correctness ----
test_that("get_fit_stream() works with correct inputs", {
  #' @description Test that FIMS::get_fit_stream(fit, stream_label, module_id) returns only rows matching both filters.
  result <- FIMS::get_fit_stream(fit, stream_label = "landings_expected", module_id = 1L)
  expect_true(all(result[["label"]] == "landings_expected"))
  expect_true(all(result[["module_id"]] == 1L))

  #' @description Test that FIMS::get_fit_stream() accepts a pre-augmented tibble and filters correctly.
  aug <- generics::augment(fit)
  result_from_aug <- FIMS::get_fit_stream(aug, stream_label = "landings_expected")
  expect_true(all(result_from_aug[["label"]] == "landings_expected"))

  #' @description Test that FIMS::get_fit_stream(fit) with no filters returns the same tibble as augment(fit).
  expect_equal(
    object = nrow(FIMS::get_fit_stream(fit)),
    expected = nrow(generics::augment(fit))
  )
})

## Edge handling ----
test_that("get_fit_stream() returns correct outputs for edge cases", {
  #' @description Test that FIMS::get_fit_stream(fit, stream_label = "does_not_exist") returns zero rows without error.
  expect_equal(
    object = nrow(FIMS::get_fit_stream(fit, stream_label = "does_not_exist")),
    expected = 0L
  )
})

## Error handling ----
# No built-in errors or warnings for FIMS::get_fit_stream().
